var e=[{id:`L3_1`,type:`dialog`,speaker:`POOR_NPC_NULL_B`,text:{KOREA:`으아아! 벽이 날아갔다!`,JPN:`うわあ！　壁がぶっ飛んだ！`,ENG:`Yikes! She blew the wall off!`,TWN:`哇啊啊！牆壁被打飛咧！`},stage:{bg:`CLOSE`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`CIEL_ACADEMY_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:`POOR_NPC_NULL_A`,text:{KOREA:`무, 무슨 힘이 이렇게 세?!`,JPN:`な、なんて馬鹿力なんだよ！！`,ENG:`H-how is she so strong?!`,TWN:`是，女浩克嗎？！`},stage:{bg:`CLOSE`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`CIEL_ACADEMY_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:null}}},{id:`L5_1`,type:`dialog`,speaker:`CIEL_ACADEMY_NULL_NULL`,text:{KOREA:`사람을 해쳐본 사람은… 피냄새가 난다오.`,JPN:`人を殺めた者は……血の匂いがするのです。`,ENG:`People who have harmed others... have a distinct smell of blood.`,TWN:`曾經傷害過人的人…都會散發血腥味。`},stage:{bg:`CLOSE`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`CIEL_ACADEMY_NULL_NULL`,face:`UNIT_PRIDE`},C:null,R:null}}},{id:`L7_1`,type:`dialog`,speaker:`POOR_NPC_NULL_B`,text:{KOREA:`뭣? 내… 냄새?`,JPN:`は？　に……匂い？`,ENG:`What? B-blood?`,TWN:`蛤？血…血腥味？`},stage:{bg:`CLOSE`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`CIEL_ACADEMY_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:null}}},{id:`L8_1`,type:`dialog`,speaker:`CIEL_ACADEMY_NULL_NULL`,text:{KOREA:`그대들에겐 피냄새가 나지 않소. 사람을 해칠 배짱도 없어 보이는구려.`,JPN:`貴殿らからは血の匂いがしません。人を殺める度胸もないようですね。`,ENG:`You do not smell of blood. It seems that you do not have the guts to harm people.`,TWN:`你們身上沒有血腥味，看起來也沒那個膽量傷害人。`},stage:{bg:`CLOSE`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`CIEL_ACADEMY_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:null}}},{id:`L9_1`,type:`dialog`,speaker:`CIEL_ACADEMY_NULL_NULL`,text:{KOREA:`그런데 어찌하여 백주 대낮에 사람을 납치하는 것이요?`,JPN:`ところで、どうして真昼間に人を拉致するのですか？`,ENG:`Then, why would you kidnap me in broad daylight?`,TWN:`為什麼要在光天化日之下綁架人？`},stage:{bg:`CLOSE`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`CIEL_ACADEMY_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:null}}},{id:`L11_1`,type:`dialog`,speaker:`POOR_NPC_NULL_A`,text:{KOREA:`어쩔 수 없잖아. 두목이 시켰는데 안 따르면 우린 침식체 밥이 될 거라고!`,JPN:`仕方ねえだろ。親分の指示に従わねえと、俺らは侵食体の餌にされちまうんだよ！`,ENG:`We had no other choice. If we don't follow boss's orders, we become C.O. food!`,TWN:`有什麼辦法？我們也是奉命行事，要是不聽話，老大會拿我們去餵侵蝕體的！`},stage:{bg:`CLOSE`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`CIEL_ACADEMY_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:null}}},{id:`L12_1`,type:`dialog`,speaker:`POOR_NPC_NULL_B`,text:{KOREA:`임마, 조용히 해! 물어본다고 그렇게 순순히 대답해주면 어떡하냐!`,JPN:`こら、黙ってろ！　聞かれた質問に素直に答えてどうする！`,ENG:`Hey, watch your mouth! You're spilling all the beans here!`,TWN:`喂，你閉嘴！！怎麼人家問什麼你就回答什麼！`},stage:{bg:`CLOSE`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`CIEL_ACADEMY_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:null}}},{id:`L14_1`,type:`dialog`,speaker:`POOR_NPC_NULL_BOSS`,text:{KOREA:`어이! 무슨 소란이지?`,JPN:`おい！　何の騒ぎだ。`,ENG:`Hey! What's all this ruckus?!`,TWN:`喂！吵什麼吵？`},stage:{bg:`CLOSE`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L15_1`,type:`dialog`,speaker:`POOR_NPC_NULL_B`,text:{KOREA:`헉…! 두목님?!`,JPN:`はっ……！　親分！？`,ENG:`*Gasp* Boss?!`,TWN:`呃…！老大？！`},stage:{bg:`CLOSE`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L16_1`,type:`dialog`,speaker:`CIEL_ACADEMY_NULL_NULL`,text:{KOREA:`그대가 본인을 납치한 자요?`,JPN:`貴殿がお頭ですか？`,ENG:`Are you the one who ordered my kidnapping?`,TWN:`就是你綁架在下的嗎？`},stage:{bg:`CLOSE`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`CIEL_ACADEMY_NULL_NULL`,face:`UNIT_SERIOUS`},C:null,R:null}}},{id:`L18_1`,type:`dialog`,speaker:`POOR_NPC_NULL_BOSS`,text:{KOREA:`뭐야?! 분명 묶어두라고 했을 텐데 어떻게 풀려난 거지?`,JPN:`何だ！？　縛っておけと言ったはずだぞ？`,ENG:`Huh?! I thought I told you to tie her up! How did she get free?`,TWN:`搞什麼？！不是叫你們把她綁起來嗎？她為什麼可以行動自如？`},stage:{bg:`CLOSE`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`CIEL_ACADEMY_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:null}},sfx:`FX_CUTSCEN_NOISE_RUSTLE_04`},{id:`L19_1`,type:`dialog`,speaker:`POOR_NPC_NULL_B`,text:{KOREA:`그… 그게 힘을 팍하고 주니까 뚜둑 하고 끊어지던뎁쇼?`,JPN:`それが……コイツが馬鹿力で切っちまったんす。`,ENG:`Well... she just ripped the rope with her brute strength...`,TWN:`因為…她力氣好大，繩子根本綁不住她。`},stage:{bg:`CLOSE`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`CIEL_ACADEMY_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:null}}},{id:`L20_1`,type:`dialog`,speaker:`POOR_NPC_NULL_A`,text:{KOREA:`저, 저희는 분명 단단히 묶어 뒀어요!`,JPN:`お、俺らはちゃんと縛りましたよ！`,ENG:`W-we tied her up real good! I swear!`,TWN:`我，我們明明有把她綁很緊！`},stage:{bg:`CLOSE`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`CIEL_ACADEMY_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:null}}},{id:`L21_1`,type:`dialog`,speaker:`POOR_NPC_NULL_BOSS`,text:{KOREA:`이 멍청한 놈들이…! 조금 있다 보자!`,JPN:`このアホどもが……！　覚悟しておけよ！`,ENG:`You idiots...! I'll deal with you later!`,TWN:`你們這些沒用的東西…！看我等下怎麼處理你們！`},stage:{bg:`CLOSE`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`CIEL_ACADEMY_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:null}}}];export{e as default};